import { Injectable, inject, signal, computed } from '@angular/core';
import { Auth, User, authState } from '@angular/fire/auth';
import { toSignal } from '@angular/core/rxjs-interop';

/**
 * Signal-basierter Auth-State.
 * Wird von AuthService befüllt und kann in der gesamten App
 * via inject(AuthStateService) genutzt werden.
 */
@Injectable({ providedIn: 'root' })
export class AuthStateService {
  private readonly auth = inject(Auth);

  /** Raw Firebase User als Signal (null = nicht eingeloggt) */
  readonly currentUser = toSignal<User | null>(authState(this.auth), {
    initialValue: null,
  });

  /** true sobald authState mindestens einmal einen Wert geliefert hat */
  readonly isLoading = signal(true);

  /** true wenn User eingeloggt ist */
  readonly isAuthenticated = computed(() => this.currentUser() !== null);

  /** true wenn E-Mail verifiziert */
  readonly isEmailVerified = computed(
    () => this.currentUser()?.emailVerified === true
  );

  /** Anzeigename des Users */
  readonly displayName = computed(
    () => this.currentUser()?.displayName ?? this.currentUser()?.email ?? null
  );

  /** Avatar-URL */
  readonly photoURL = computed(() => this.currentUser()?.photoURL ?? null);

  /** User-UID */
  readonly uid = computed(() => this.currentUser()?.uid ?? null);

  /**
   * Liest die Custom Claim 'role' aus dem Firebase ID-Token.
   * Wird nach Login und bei Token-Refresh aktualisiert.
   */
  readonly role = signal<'user' | 'super_admin'>('user');

  constructor() {
    authState(this.auth).subscribe((user) => {
      this.isLoading.set(false);
      if (user) {
        user.getIdTokenResult().then((result) => {
          const claim = result.claims['role'] as string | undefined;
          this.role.set(claim === 'super_admin' ? 'super_admin' : 'user');
        });
      } else {
        this.role.set('user');
      }
    });
  }
}
