import {
  EnvironmentProviders,
  makeEnvironmentProviders,
} from '@angular/core';
import { initializeApp } from 'firebase/app';
import { provideFirebaseApp } from '@angular/fire/app';
import { getAuth, provideAuth } from '@angular/fire/auth';
import { FIREBASE_AUTH_CONFIG, FirebaseAuthConfig } from './auth-module.config';
import { AuthService } from './auth.service';
import { AuthStateService } from './auth-state.service';

/**
 * provideFirebaseAuth() – die einzige Funktion die in app.config.ts
 * aufgerufen werden muss um das Auth-Modul vollständig einzubinden.
 *
 * @example
 * // apps/web/src/app/app.config.ts
 * import { provideFirebaseAuth } from '../../libs/firebase-auth';
 *
 * export const appConfig: ApplicationConfig = {
 *   providers: [
 *     provideRouter(appRoutes),
 *     provideFirebaseAuth({
 *       firebaseConfig: environment.firebase,
 *       redirectAfterLogin: '/app/dashboard',
 *       redirectAfterLogout: '/login',
 *     })
 *   ]
 * };
 */
export function provideFirebaseAuth(
  config: FirebaseAuthConfig
): EnvironmentProviders {
  return makeEnvironmentProviders([
    provideFirebaseApp(() => initializeApp(config.firebaseConfig)),
    provideAuth(() => getAuth()),
    {
      provide: FIREBASE_AUTH_CONFIG,
      useValue: config,
    },
    AuthService,
    AuthStateService,
  ]);
}
