import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import {
  Auth,
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  signOut,
  sendPasswordResetEmail,
  sendEmailVerification,
  GoogleAuthProvider,
  signInWithPopup,
  updateProfile,
  User,
} from '@angular/fire/auth';
import { from, Observable } from 'rxjs';
import { FIREBASE_AUTH_CONFIG } from './auth-module.config';

/**
 * AuthService – Wrapper um Firebase Authentication.
 * Kapselt alle Auth-Operationen. Kein direkter Firebase-Import
 * in Komponenten nötig.
 */
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly auth = inject(Auth);
  private readonly router = inject(Router);
  private readonly config = inject(FIREBASE_AUTH_CONFIG);

  private get redirectAfterLogin(): string {
    return this.config.redirectAfterLogin ?? '/app/dashboard';
  }

  private get redirectAfterLogout(): string {
    return this.config.redirectAfterLogout ?? '/login';
  }

  // ─── Email/Passwort ────────────────────────────────────────────────────────

  /**
   * Login mit E-Mail und Passwort.
   * Navigiert nach Erfolg zu redirectAfterLogin.
   */
  async loginWithEmail(email: string, password: string): Promise<void> {
    await signInWithEmailAndPassword(this.auth, email, password);
    await this.router.navigateByUrl(this.redirectAfterLogin);
  }

  /**
   * Neuen User registrieren mit E-Mail + Passwort.
   * Setzt displayName und sendet Verifikations-E-Mail.
   */
  async register(
    email: string,
    password: string,
    displayName?: string
  ): Promise<void> {
    const credential = await createUserWithEmailAndPassword(
      this.auth,
      email,
      password
    );
    if (displayName) {
      await updateProfile(credential.user, { displayName });
    }
    await sendEmailVerification(credential.user);
  }

  // ─── Social Login ──────────────────────────────────────────────────────────

  /**
   * Google OAuth Login via Popup.
   * Navigiert nach Erfolg zu redirectAfterLogin.
   */
  async loginWithGoogle(): Promise<void> {
    const provider = new GoogleAuthProvider();
    await signInWithPopup(this.auth, provider);
    await this.router.navigateByUrl(this.redirectAfterLogin);
  }

  // ─── Logout ────────────────────────────────────────────────────────────────

  async logout(): Promise<void> {
    await signOut(this.auth);
    await this.router.navigateByUrl(this.redirectAfterLogout);
  }

  // ─── Passwort-Reset ────────────────────────────────────────────────────────

  async sendPasswordReset(email: string): Promise<void> {
    await sendPasswordResetEmail(this.auth, email);
  }

  // ─── E-Mail-Verifikation ───────────────────────────────────────────────────

  async sendEmailVerification(): Promise<void> {
    const user = this.auth.currentUser;
    if (user) {
      await sendEmailVerification(user);
    }
  }

  // ─── Token / Claims ────────────────────────────────────────────────────────

  /**
   * Gibt den aktuellen Firebase ID-Token zurück.
   * Nützlich für Backend-Calls.
   */
  async getIdToken(forceRefresh = false): Promise<string | null> {
    return (await this.auth.currentUser?.getIdToken(forceRefresh)) ?? null;
  }

  /** Aktueller Firebase User (synchron) */
  get currentUser(): User | null {
    return this.auth.currentUser;
  }
}
