import { InjectionToken } from '@angular/core';

export interface FirebaseAuthConfig {
  /**
   * Firebase-Konfiguration des jeweiligen Projekts.
   * Kommt aus environments/environment.ts der App.
   */
  firebaseConfig: {
    apiKey: string;
    authDomain: string;
    projectId: string;
    storageBucket?: string;
    messagingSenderId?: string;
    appId: string;
  };
  /** Route nach erfolgreichem Login. Default: '/app/dashboard' */
  redirectAfterLogin?: string;
  /** Route nach Logout. Default: '/login' */
  redirectAfterLogout?: string;
  /** Route zum Login, wenn Guard anschlägt. Default: '/login' */
  loginRoute?: string;
}

export const FIREBASE_AUTH_CONFIG = new InjectionToken<FirebaseAuthConfig>(
  'FIREBASE_AUTH_CONFIG'
);
